namespace System.Runtime.CompilerServices
{
    /// <summary>
    /// Provides a common interface for accessing the contents of a union type at runtime.
    /// </summary>
    /// <remarks>
    /// <para>
    /// The C# compiler automatically implements this interface on types generated by union declarations.
    /// User-defined types annotated with <see cref="UnionAttribute" /> may also implement this interface
    /// to participate in union behaviors such as implicit union conversions, union pattern matching,
    /// and switch exhaustiveness checking.
    /// </para>
    /// <para>
    /// The <see cref="Value" /> property is expected to return <see langword="null" /> or a value of
    /// one of the union's case types. A union's case types are determined by its single-parameter
    /// constructors (or static <c>Create</c> factory methods when a union member provider is used).
    /// </para>
    /// <para>
    /// For more information, see the
    /// <see href="https://github.com/dotnet/csharplang/blob/main/proposals/unions.md">C# unions proposal</see>.
    /// </para>
    /// </remarks>
    /// <seealso cref="UnionAttribute" />
    public interface IUnion
    {
        /// <summary>
        /// Gets the value contained in the union, or <see langword="null" /> if the union has no value.
        /// </summary>
        /// <value>
        /// The current value of the union as one of its case types, or <see langword="null" />.
        /// </value>
        object? Value { get; }
    }
}
